// Find the most recent Patch Tuesday release
const updates = $input.first().json.value;

const sorted = [...updates].sort((a, b) =>
  new Date(b.InitialReleaseDate).getTime() - new Date(a.InitialReleaseDate).getTime()
);

const latest = sorted[0];
return [{ json: { id: latest.ID, title: latest.DocumentTitle, releaseDate: latest.InitialReleaseDate } }];

const doc = $input.first().json;

// Build product name lookup from ProductTree
const productNames = {};
for (const p of (doc.ProductTree?.FullProductName ?? [])) {
  productNames[p.ProductID] = p.Value;
}

// Get a specific threat type value
function getThreat(threats, type) {
  if (!Array.isArray(threats)) return null;
  const found = threats.find(t => t.Type === type);
  return found?.Description?.Value ?? null;
}

// Check all threats for exploitation-in-the-wild keywords
function isExploited(threats) {
  if (!Array.isArray(threats)) return false;
  return threats.some(t => {
    const v = (t.Description?.Value ?? '').toLowerCase();
    return v.includes('exploit') && (v.includes('detected') || v.includes('wild'));
  });
}

// Map a product name string to a broad product family
function getFamily(name) {
  if (!name) return null;
  if (/windows (10|11|server)/i.test(name)) return 'Windows';
  if (/microsoft 365|office|word|excel|powerpoint|outlook/i.test(name)) return 'Microsoft 365 / Office';
  if (/exchange/i.test(name)) return 'Exchange Server';
  if (/azure/i.test(name)) return 'Azure';
  if (/sql server/i.test(name)) return 'SQL Server';
  if (/sharepoint/i.test(name)) return 'SharePoint';
  if (/edge|internet explorer/i.test(name)) return 'Edge / IE';
  if (/\.net|visual studio/i.test(name)) return '.NET / Visual Studio';
  return null;
}

// The CVRF document includes both new CVEs and previously disclosed CVEs
// that received revised patches this month. Deduplicate by CVE ID and
// skip advisory entries (ADV-XXXXX) which are not individual CVEs.
const seen = new Set();
const vulns = (doc.Vulnerability ?? []).filter(v => {
  const id = v.CVE ?? '';
  if (!id.startsWith('CVE-') || seen.has(id)) return false;
  seen.add(id);
  return true;
});

let critical = 0, important = 0, moderate = 0, exploitedCount = 0;
const patchNow = [];   // critical + actively exploited in the wild
const patchWeek = [];  // critical RCE, not yet exploited
const productFamilies = new Set();

for (const v of vulns) {
  const severity = getThreat(v.Threats, 0);
  const impact = getThreat(v.Threats, 1);
  const exploitedInWild = isExploited(v.Threats);

  if (severity === 'Critical') critical++;
  else if (severity === 'Important') important++;
  else if (severity === 'Moderate') moderate++;

  if (exploitedInWild) exploitedCount++;

  // Collect affected product families
  for (const ps of (v.ProductStatuses ?? [])) {
    for (const pid of (ps.ProductID ?? [])) {
      const family = getFamily(productNames[pid]);
      if (family) productFamilies.add(family);
    }
  }

  const entry = { cve: v.CVE, title: v.Title?.Value ?? v.CVE, impact };

  if (exploitedInWild && severity === 'Critical') {
    if (patchNow.length < 5) patchNow.push(entry);
  } else if (severity === 'Critical' && impact?.includes('Remote Code Execution')) {
    if (patchWeek.length < 5) patchWeek.push(entry);
  }
}

const monthTitle = typeof doc.DocumentTitle === 'string'
  ? doc.DocumentTitle
  : (doc.DocumentTitle?.Value ?? 'Unknown');

return [{
  json: {
    month: monthTitle,
    stats: {
      total: vulns.length,
      critical,
      important,
      moderate,
      exploitedInWild: exploitedCount,
    },
    patchNow,
    patchWeek,
    productFamilies: Array.from(productFamilies),
  }
}];
